entryCriteria.formula:
AND(CreatedBy.ManagerId <> CC_FCA_Finance__c && CreatedBy.ManagerId <> CC_FCA_Finance__r.ManagerId && ISPICKVAL(CC_Status__c,'Submitted'), (OR( (OR(CONTAINS(CreatedBy.UserRole.Name,'Advisor'),CONTAINS(CreatedBy.UserRole.Name,'Specialist')) && !(ISPICKVAL(CreatedBy.CC_Unique_Business_Role__c,'Jr. Operations Manager')) && (CC_CNAUpdate__c==true || CC_CNAUpdate__c==false) && ( ((!(ISPICKVAL(CC_CheckCategory__c,'Recall')) || (ISPICKVAL(CC_CheckCategory__c,'Recall'))) && CC_Junior_Operations_Manager__c = true && (ISBLANK(NAFTA_RecallAmount__c) && CC_CheckAmount__c > 10000) ) || ((!(ISPICKVAL(CC_CheckCategory__c,'Recall'))) || (ISPICKVAL(CC_CheckCategory__c,'Recall')) && CC_Junior_Operations_Manager__c = false && (ISBLANK(NAFTA_RecallAmount__c) && CC_CheckAmount__c > 5000)) || ((ISPICKVAL(CC_CheckCategory__c,'Recall')) && CC_Junior_Operations_Manager__c = false && (!ISBLANK(NAFTA_RecallAmount__c) && CC_CheckAmount__c > NAFTA_RecallAmount__c && CC_CheckAmount__c > 5000)) || ((ISPICKVAL(CC_CheckCategory__c,'Recall')) && CC_Junior_Operations_Manager__c = true && (!ISBLANK(NAFTA_RecallAmount__c) && CC_CheckAmount__c > NAFTA_RecallAmount__c && CC_CheckAmount__c > 10000)))),
(CONTAINS(CreatedBy.UserRole.Name,'Supervisor') && !(ISPICKVAL(CreatedBy.CC_Unique_Business_Role__c,'Jr. Operations Manager')) && (CC_CNAUpdate__c==true || CC_CNAUpdate__c==false) && CC_Junior_Operations_Manager__c = true && ( ((!(ISPICKVAL(CC_CheckCategory__c,'Recall')) || (ISPICKVAL(CC_CheckCategory__c,'Recall'))) && (ISBLANK(NAFTA_RecallAmount__c) && CC_CheckAmount__c > 5000)) ||((ISPICKVAL(CC_CheckCategory__c,'Recall')) && ((!ISBLANK(NAFTA_RecallAmount__c) && CC_CheckAmount__c > NAFTA_RecallAmount__c && CC_CheckAmount__c > 5000)))))
)))

AND(ISPICKVAL(CC_Status__c, 'Submitted')&& CC_Junior_Operations_Manager__c = true && !(ISPICKVAL(CreatedBy.CC_Unique_Business_Role__c,'Jr. Operations Manager')),(OR(
(OR(CONTAINS(CreatedBy.UserRole.Name, 'Advisor' ),
CONTAINS(CreatedBy.UserRole.Name, 'Specialist')
) &&((!(ISBLANK(NAFTA_RecallAmount__c))&&(CC_CheckAmount__c>NAFTA_RecallAmount__c)&&(CC_CheckAmount__c>25000))||(ISBLANK(NAFTA_RecallAmount__c)&&CC_CheckAmount__c >25000))&&(ISPICKVAL(CC_CheckCategory__c,'Recall'))),
(OR(CONTAINS(CreatedBy.UserRole.Name, 'Advisor' ),
CONTAINS(CreatedBy.UserRole.Name, 'Specialist')
) &&!(ISPICKVAL(CC_CheckCategory__c,'Recall'))&&CC_CheckAmount__c >25000)
)))

OR(
AND( CC_CheckAmount__c > 5000,OR(OR(CONTAINS(CreatedBy.UserRole.Name,'Advisor'),CONTAINS(CreatedBy.UserRole.Name,'Specialist')),CONTAINS(CreatedBy.UserRole.Name,'Supervisor'),ISPICKVAL(CreatedBy.CC_Unique_Business_Role__c,'Jr. Operations Manager'),CONTAINS(CreatedBy.UserRole.Name,'Operation Head - USA'),CONTAINS(CreatedBy.UserRole.Name, 'Special Investigation team'),CONTAINS(CreatedBy.UserRole.Name,'CRM'),CONTAINS(CreatedBy.UserRole.Name,'Area Manager'),CONTAINS(CreatedBy.UserRole.Name, 'Level3 Agent'),CONTAINS(CreatedBy.UserRole.Name, 'Top Care Agent - USA')
)
),
AND(CC_CheckAmount__c > 0,OR(CONTAINS(CreatedBy.UserRole.Name,'FCA Sr Professional - USA'),CONTAINS(CreatedBy.UserRole.Name,'FCA RO / Manager (USA)'))
))
